const row = $json;
const e = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const arr = (value) => { if (Array.isArray(value)) return value; if (typeof value === 'string') { try { return JSON.parse(value); } catch {} } return []; };
const obj = (value) => { if (value && typeof value === 'object' && !Array.isArray(value)) return value; if (typeof value === 'string') { try { return JSON.parse(value); } catch {} } return {}; };
const projects = arr(row.top_projects);
const categories = arr(row.top_categories);
const latest = arr(row.latest_items);
const actions = arr(row.next_actions);
const relations = obj(row.relation_counts);
const storageMb = (Number(row.current_bytes || 0) / 1000000).toFixed(1);
const storagePercent = Number(row.threshold_bytes || 0) > 0 ? ((Number(row.current_bytes || 0) / Number(row.threshold_bytes)) * 100).toFixed(1) : '0.0';
const sections = [
  `<b>🧠 Щотижневий Inbox Digest</b>
${e(row.period_start)} — ${e(row.period_end)}`,
  `<b>За тиждень</b>
Нових матеріалів: ${Number(row.new_count || 0)}
Готових у пам’яті: ${Number(row.ready_total || 0)}
Потребують review: ${Number(row.review_count || 0)}
Дублікатів: ${Number(row.duplicate_count || 0)}`,
  projects.length ? `<b>Проєкти</b>
${projects.map((item) => `• ${e(item.name)} — ${Number(item.count || 0)}`).join('\n')}` : '',
  categories.length ? `<b>Категорії</b>
${categories.map((item) => `• ${e(item.name)} — ${Number(item.count || 0)}`).join('\n')}` : '',
  Object.keys(relations).length ? `<b>Нові зв’язки</b>
${Object.entries(relations).map(([type, count]) => `• ${e(type)} — ${Number(count || 0)}`).join('\n')}` : '',
  latest.length ? `<b>Останні матеріали</b>
${latest.map((item) => `• <code>${e(item.short_id)}</code> ${e(item.title)} · ${e(item.project)}`).join('\n')}` : '',
  actions.length ? `<b>Запропоновані дії</b>
${actions.map((action) => `• ${e(action)}`).join('\n')}` : '',
  `<b>B2</b>
${storageMb} MB · ${storagePercent}% від порогу 7 GB`,
  `<code>/review</code> · <code>/duplicates</code> · <code>/recent</code>`
].filter(Boolean);
return [{ json: { ...row, reply: sections.join('\n\n').slice(0, 4000) } }];
